INSERT INTO product_categories(tenant_id,name) SELECT '11111111-1111-1111-1111-111111111111',name FROM (VALUES('Stick'),('Mochi'),('Cup'),('Cone')) c(name) ON CONFLICT DO NOTHING;
INSERT INTO products(tenant_id,category_id,sku,name,category,unit,price,status) SELECT '11111111-1111-1111-1111-111111111111',c.id,v.sku,v.name,v.category,'Karton',v.price,v.status FROM (VALUES
('AIC-NAN-065','AICE Nanas 65g','Stick',72000,'Aktif'),('AIC-MOV-045','AICE Mochi Vanilla 45g','Mochi',96000,'Stok Kritis'),('AIC-CHO-060','AICE Chocolate Crispy 60g','Stick',108000,'Aktif'),('AIC-COR-060','AICE Sweet Corn 60g','Stick',84000,'Stok Kritis'),
('AIC-MEL-055','AICE Milk Melon 55g','Stick',78000,'Aktif'),('AIC-MAN-060','AICE Mango Slushy 60ml','Cup',90000,'Aktif'),('AIC-MGT-030','AICE Mochi Green Tea 30g','Mochi',102000,'Stok Kritis'),('AIC-MIK-090','AICE Miki-Miki 90ml','Cone',120000,'Aktif'),
('AIC-STR-070','AICE Strawberry Crispy','Stick',108000,'Aktif'),('AIC-COF-080','AICE Coffee Crispy','Stick',114000,'Aktif'),('AIC-SUN-100','AICE Sundae Chocolate','Cup',132000,'Nonaktif'),('AIC-TWO-075','AICE Two Colors','Stick',90000,'Aktif')) v(sku,name,category,price,status) JOIN product_categories c ON c.tenant_id='11111111-1111-1111-1111-111111111111' AND c.name=v.category ON CONFLICT DO NOTHING;
INSERT INTO outlets(tenant_id,code,name,area,address,phone,npwp_nik,nitku,gps_lat,gps_lng,sales_pic_id,credit_limit,receivable_balance,status)
INSERT INTO warehouses(tenant_id,code,name,address) VALUES ('11111111-1111-1111-1111-111111111111','WH-TGR','Gudang Utama Tangerang','Jl. Industri Tangerang No. 18'),('11111111-1111-1111-1111-111111111111','WH-JKB','Gudang Jakarta Barat','Jl. Daan Mogot No. 92') ON CONFLICT DO NOTHING;
INSERT INTO stock_items(tenant_id,warehouse_id,product_id,batch_no,available_qty,minimum_qty,status) SELECT p.tenant_id,w.id,p.id,format('B2606-%s',p.rn),18+((p.rn*17)::int%137),35,CASE WHEN 18+((p.rn*17)::int%137)<35 THEN 'Stok Kritis' ELSE 'Aman' END FROM numbered p JOIN warehouses w ON w.tenant_id=p.tenant_id AND w.code=CASE WHEN p.rn%2=0 THEN 'WH-JKB' ELSE 'WH-TGR' END ON CONFLICT DO NOTHING;
INSERT INTO stock_movements(tenant_id,warehouse_id,product_id,movement_type,quantity,reference_no) SELECT p.tenant_id,w.id,p.id,CASE WHEN row_number() OVER()%3=0 THEN 'OUT' ELSE 'IN' END,20+(row_number() OVER()*5)::int,format('MOV-2606-%s',lpad(row_number() OVER()::text,3,'0')) FROM products p JOIN warehouses w ON w.tenant_id=p.tenant_id AND w.code='WH-TGR';
INSERT INTO orders(tenant_id,order_no,outlet_id,sales_id,order_date,payment_method,due_date,subtotal,discount,ppn,total,status)
INSERT INTO order_items(tenant_id,order_id,product_id,qty,price,discount,subtotal) SELECT o.tenant_id,o.id,p.id,2+(o.rn::int%4),p.price,0,(2+(o.rn::int%4))*p.price FROM numbered_orders o CROSS JOIN LATERAL (SELECT * FROM products WHERE tenant_id=o.tenant_id ORDER BY sku OFFSET ((o.rn-1)::int%12) LIMIT 1) p;
INSERT INTO delivery_orders(tenant_id,do_no,order_id,outlet_id,driver_id,vehicle,scheduled_at,status,pod_status,delivered_at) SELECT o.tenant_id,replace(o.order_no,'SO','DO'),o.id,o.outlet_id,u.id,(ARRAY['B 9124 KCD','B 8831 UYT','B 7012 XZA'])[1+((o.rn-1)::int%3)],TIMESTAMPTZ '2026-06-29 07:00:00+07'+(o.rn*interval '45 minutes'),(ARRAY['Siap Kirim','Dalam Perjalanan','Terkirim','Gagal'])[1+((o.rn-1)::int%4)],(ARRAY['Menunggu','Menunggu','Tersedia','Tidak Ada'])[1+((o.rn-1)::int%4)],CASE WHEN o.rn%4=3 THEN TIMESTAMPTZ '2026-06-29 10:00:00+07' ELSE NULL END FROM numbered_orders o JOIN users u ON u.email=(ARRAY['andi@aice-distributor.id','rizal@aice-distributor.id','fajar@aice-distributor.id'])[1+((o.rn-1)::int%3)];
INSERT INTO delivery_order_items(tenant_id,delivery_order_id,product_id,qty) SELECT d.tenant_id,d.id,oi.product_id,oi.qty FROM delivery_orders d JOIN order_items oi ON oi.order_id=d.order_id;
INSERT INTO receivables(tenant_id,invoice_no,outlet_id,order_id,invoice_date,due_date,amount,paid_amount,balance,aging_bucket,status) SELECT o.tenant_id,replace(o.order_no,'SO','INV'),o.outlet_id,o.id,o.order_date,o.due_date,o.total,CASE WHEN row_number() OVER()%3=0 THEN o.total*.4 ELSE 0 END,CASE WHEN row_number() OVER()%3=0 THEN o.total*.6 ELSE o.total END,(ARRAY['Belum Jatuh Tempo','1-30 Hari','31-60 Hari','>60 Hari'])[1+((row_number() OVER()-1)::int%4)],(ARRAY['Lancar','Jatuh Tempo','Terlambat'])[1+((row_number() OVER()-1)::int%3)] FROM orders o ON CONFLICT DO NOTHING;
INSERT INTO payments(tenant_id,receivable_id,payment_no,payment_date,amount,method,reference_no) SELECT r.tenant_id,r.id,format('PAY-2606-%s',lpad(row_number() OVER()::text,3,'0')),DATE '2026-06-29'-(row_number() OVER()::int%6),r.amount-r.balance,'Transfer Bank',format('TRX-%s',10000+row_number() OVER()) FROM receivables r WHERE r.paid_amount>0 ON CONFLICT DO NOTHING;
INSERT INTO tax_invoices(tenant_id,invoice_no,outlet_id,npwp_nik,nitku,dpp,ppn,total,validation_status,export_status) SELECT r.tenant_id,r.invoice_no,r.outlet_id,o.npwp_nik,o.nitku,ord.subtotal-ord.discount,ord.ppn,ord.total,CASE WHEN o.npwp_nik IS NULL OR o.nitku IS NULL THEN 'Invalid' ELSE 'Valid' END,CASE WHEN row_number() OVER()%7=0 THEN 'Sudah' ELSE 'Belum' END FROM receivables r JOIN outlets o ON o.id=r.outlet_id JOIN orders ord ON ord.id=r.order_id ON CONFLICT DO NOTHING;
INSERT INTO tax_export_logs(tenant_id,file_name,period,invoice_count,status) VALUES ('11111111-1111-1111-1111-111111111111','Faktur_Pajak_Mei_2026.xml','2026-05',42,'success'),('11111111-1111-1111-1111-111111111111','Faktur_Pajak_Jun_2026_01.xml','2026-06',12,'success');
