BEGIN;
SELECT '11111111-1111-1111-1111-111111111111',format('OUT-%s',lpad(g::text,3,'0')),names[g],areas[1+((g-1)%4)],format('Jl. Raya Distributor No. %s',11+g),format('0812-3456-%s',1000+g),CASE WHEN g%7=0 THEN NULL ELSE format('31.728.%s.2-401.000',100+g) END,CASE WHEN g%6=0 THEN NULL ELSE format('NITKU-401-%s',100+g) END,-6.1700000-g/10000.0,106.7400000+g/10000.0,(SELECT id FROM users WHERE email='rina@aice-distributor.id'),15000000+((g-1)%4)*5000000,((g-1)%5)*2800000,CASE WHEN g IN(6,15) THEN 'Diblokir' ELSE 'Aktif' END
FROM generate_series(1,20) g CROSS JOIN (SELECT ARRAY['Toko Sejahtera','Sumber Rejeki Mart','Maju Bersama','Amanah Minimarket','Toko Makmur','Prima Swalayan','Toko Harapan','Mega Mart','Berkah Jaya','Toko Melati','Sinar Baru','Family Mart','Rizki Abadi','Toko Sentosa','Cahaya Mini Market','Toko Barokah','Bintang Swalayan','Toko Indah','Kurnia Mart','Sahabat Kita'] names,ARRAY['Jakarta Barat','Tangerang','Jakarta Utara','Bekasi'] areas) x ON CONFLICT DO NOTHING;
WITH numbered AS (SELECT p.*,row_number() OVER(ORDER BY p.sku) rn FROM products p)
SELECT '11111111-1111-1111-1111-111111111111',format('SO-2606-%s',lpad(g::text,3,'0')),(SELECT id FROM outlets ORDER BY code OFFSET g-1 LIMIT 1),(SELECT id FROM users WHERE email='rina@aice-distributor.id'),DATE '2026-06-29'-(g-1), 'Kredit',DATE '2026-07-13'-(g-1),1200000+g*137000,(1200000+g*137000)*.03,(1200000+g*137000)*.97*.11,(1200000+g*137000)*.97*1.11,(ARRAY['Menunggu Approval','Diproses Gudang','Siap Kirim','Terkirim'])[1+((g-1)%4)] FROM generate_series(1,20) g ON CONFLICT DO NOTHING;
WITH numbered_orders AS (SELECT o.*,row_number() OVER(ORDER BY o.order_no) rn FROM orders o)
WITH numbered_orders AS (SELECT o.*,row_number() OVER(ORDER BY o.order_no) rn FROM orders o ORDER BY o.order_no LIMIT 10)
COMMIT;
